import React, { useState, useEffect } from "react";
import { useParams, useNavigate, Link } from "react-router-dom";
import { format } from "date-fns";
import api from "../api/axios";
import { useAuth } from "../context/AuthContext";

export default function EventDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [deleting, setDeleting] = useState(false);

  useEffect(() => {
    api.get(`/events/${id}/`)
      .then(({ data }) => setEvent(data))
      .catch(() => navigate("/", { replace: true }))
      .finally(() => setLoading(false));
  }, [id, navigate]);

  const handleDelete = async () => {
    if (!window.confirm("Are you sure you want to delete this event?")) return;
    setDeleting(true);
    try {
      await api.delete(`/events/${id}/`);
      navigate("/dashboard");
    } catch {
      alert("Failed to delete event.");
      setDeleting(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (!event) return null;

  const isOwner = user && event.organizer?.id === user.id;
  const isAdmin = user?.role === "admin" || user?.is_staff;
  const imageUrl = event.image
    ? event.image.startsWith("http") ? event.image : `http://localhost:8000${event.image}`
    : null;

  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <Link to="/" className="inline-flex items-center gap-1 text-sm text-gray-500 hover:text-primary-600 mb-6 transition-colors">
        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
        </svg>
        Back to Events
      </Link>

      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        {/* Image */}
        {imageUrl ? (
          <img src={imageUrl} alt={event.title} className="w-full h-72 object-cover" />
        ) : (
          <div className="w-full h-48 bg-gradient-to-br from-primary-100 to-primary-200 flex items-center justify-center">
            <svg className="w-16 h-16 text-primary-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
            </svg>
          </div>
        )}

        <div className="p-6 sm:p-8">
          <div className="flex flex-wrap gap-2 mb-4">
            {event.category_detail && (
              <span className="bg-primary-50 text-primary-700 text-xs font-medium px-3 py-1 rounded-full">
                {event.category_detail.name}
              </span>
            )}
            {event.is_featured && (
              <span className="bg-yellow-50 text-yellow-700 text-xs font-medium px-3 py-1 rounded-full">
                ★ Featured
              </span>
            )}
            <span className={`text-xs font-medium px-3 py-1 rounded-full ${
              event.status === "approved" ? "bg-green-50 text-green-700" :
              event.status === "rejected" ? "bg-red-50 text-red-700" :
              "bg-gray-50 text-gray-700"
            }`}>
              {event.status.charAt(0).toUpperCase() + event.status.slice(1)}
            </span>
          </div>

          <h1 className="text-3xl font-bold text-gray-900 mb-6">{event.title}</h1>

          <div className="grid sm:grid-cols-2 gap-4 mb-6">
            <div className="flex items-start gap-3">
              <div className="w-9 h-9 rounded-lg bg-primary-50 flex items-center justify-center shrink-0">
                <svg className="w-5 h-5 text-primary-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                </svg>
              </div>
              <div>
                <p className="text-xs text-gray-500 font-medium">Date & Time</p>
                <p className="text-sm text-gray-900">{format(new Date(event.date), "EEEE, MMMM d, yyyy")}</p>
                <p className="text-sm text-gray-600">{format(new Date(event.date), "h:mm a")}{event.end_date && ` – ${format(new Date(event.end_date), "h:mm a")}`}</p>
              </div>
            </div>
            <div className="flex items-start gap-3">
              <div className="w-9 h-9 rounded-lg bg-primary-50 flex items-center justify-center shrink-0">
                <svg className="w-5 h-5 text-primary-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                </svg>
              </div>
              <div>
                <p className="text-xs text-gray-500 font-medium">Location</p>
                <p className="text-sm text-gray-900">{event.location}</p>
                {event.city && <p className="text-sm text-gray-600">{event.city}</p>}
              </div>
            </div>
          </div>

          <div className="prose prose-sm max-w-none text-gray-700 mb-8">
            <h3 className="text-base font-semibold text-gray-900 mb-2">About this event</h3>
            <p className="whitespace-pre-wrap">{event.description}</p>
          </div>

          {/* Organizer */}
          <div className="border-t border-gray-100 pt-6">
            <h3 className="text-sm font-semibold text-gray-900 mb-3">Organizer</h3>
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-primary-100 flex items-center justify-center">
                <span className="text-primary-700 font-semibold text-sm">
                  {(event.organizer_name || event.organizer?.username || "?")[0].toUpperCase()}
                </span>
              </div>
              <div>
                <p className="text-sm font-medium text-gray-900">
                  {event.organizer_name || event.organizer?.get_full_name || event.organizer?.username}
                </p>
                {event.organizer_email && (
                  <a href={`mailto:${event.organizer_email}`} className="text-xs text-primary-600 hover:underline">
                    {event.organizer_email}
                  </a>
                )}
              </div>
            </div>
            {event.website && (
              <a href={event.website} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-1 mt-3 text-sm text-primary-600 hover:underline">
                Visit Website
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
                </svg>
              </a>
            )}
          </div>

          {/* Owner/Admin actions */}
          {(isOwner || isAdmin) && (
            <div className="flex gap-3 mt-6 border-t border-gray-100 pt-6">
              <Link to={`/events/${id}/edit`} className="btn-secondary text-sm">Edit Event</Link>
              <button onClick={handleDelete} disabled={deleting} className="px-4 py-2 bg-red-600 text-white text-sm font-medium rounded-lg hover:bg-red-700 transition-colors disabled:opacity-50">
                {deleting ? "Deleting..." : "Delete Event"}
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
